async (params, browser) => {
  // Search Google Maps
  await browser.open(`https://www.google.com/maps/search/${params.query}`)

  // Wait for results feed
  await browser.waitForSelector('div[role=\'feed\']', 15000)

  // Let results render
  await browser.wait(2000)

  // Scroll results feed
  await browser.scroll({ selector: '[role=\'feed\']', direction: 'down', amount: 800 })

  await browser.wait(1500)

  // Extract search results
  const search_results = await browser.evaluate(`const results = []; const feed = document.querySelector('[role="feed"]'); if (!feed) return { result_count: 0, results: [] }; const items = feed.querySelectorAll('a.hfpxzc, div[jsaction] a[href*="/maps/place/"]'); const seen = new Set(); for (let i = 0; i < items.length && results.length < 10; i++) { const link = items[i]; const href = link.href; if (seen.has(href)) continue; seen.add(href); const container = link.closest('div[jsaction]') || link.parentElement; if (!container) continue; const nameEl = container.querySelector('.qBF1Pd, .fontHeadlineSmall'); const ratingEl = container.querySelector('span[role="img"]'); const categoryEl = container.querySelector('.fontBodyMedium span[style*="color"]'); const addressEl = container.querySelectorAll('.fontBodyMedium span'); let address = ''; for (const sp of addressEl) { const t = sp.textContent.trim(); if (t.length > 10 && !t.includes('\u00b7') && !t.includes('star')) { address = t; break; } } results.push({ name: nameEl ? nameEl.textContent.trim() : (link.getAttribute('aria-label') || 'Unknown'), rating: ratingEl ? ratingEl.getAttribute('aria-label') : '', category: categoryEl ? categoryEl.textContent.trim() : '', address: address, url: href }); } return { result_count: results.length, results: results }`)

  return search_results
}
